external_knowledge:
- 'treasures' refers to the items;
- 'journey in a borrowed state' refers to items that are checked out;
- 'libraries with walls that can embrace a certain number of explorers' refers to the capacity of the library;
- 'current destination' refers to the library where the item is currently located;
- 'collection they belong to' refers to the collection the item belongs to;
- 'when they are expected to return home' refers to the due date of the item.

sql:
SELECT * 
FROM items 
WHERE collection_id = 'specific_collection_id';

SELECT type_id
FROM item_types
WHERE type_name = 'Books';

SELECT users.user_name, users.email
FROM users
INNER JOIN item_reviews ON users.user_id = item_reviews.user_id;

SELECT library_name, library_id 
FROM libraries 
WHERE capacity > 500;
